-- Patchnote 0.8.0 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.8.0', 'minor', '2026-05-08T00:00:00.000Z',
  'Plugin self-update flow, generic plugin storage, indexer + download-client connector pack',
  'Mise à jour des plugins in-app, stockage générique pour plugins, pack de connecteurs indexer + download-client',
  '[{"type":"feat","titleEn":"In-app plugin update flow with permission diff","titleFr":"Mise à jour des plugins in-app avec diff des permissions","descEn":"Plugins now self-update from inside Oscarr without an SSH session — the admin sees the upcoming version, the diff of requested permissions, and chooses between a hot reload (no downtime, applies most plugin code) and a full reboot (required when manifest perms or native deps changed). Reload vs reboot is decided by the engine, not guessed by the user.","descFr":"Les plugins se mettent maintenant à jour depuis Oscarr sans SSH — l''admin voit la version cible, le diff des permissions demandées, et choisit entre hot reload (sans downtime, applique la majorité du code plugin) et reboot complet (requis quand les permissions du manifest ou les deps natives changent). Reload vs reboot est décidé par le moteur, pas deviné par l''utilisateur."},{"type":"feat","titleEn":"Generic plugin storage API (KV + SQLite)","titleFr":"API de stockage générique pour plugins (KV + SQLite)","descEn":"Plugins gain two isolated storage primitives — a key/value store and a per-plugin SQLite database — exposed via `PluginContext.storage` and gated by the new `storage:plugin` permission. State stays scoped to the plugin and is removed with it, so the core DB schema doesn''t leak plugin concerns.","descFr":"Les plugins gagnent deux primitives de stockage isolées — un key/value store et une base SQLite par plugin — exposées via `PluginContext.storage` et gated par la nouvelle permission `storage:plugin`. L''état reste scopé au plugin et est supprimé avec lui, pour que le schéma DB du core ne se pollue pas."},{"type":"feat","titleEn":"Indexer + download-client connector pack (Prowlarr, NZBGet, SABnzbd, Transmission, Deluge)","titleFr":"Pack de connecteurs indexer + download-client (Prowlarr, NZBGet, SABnzbd, Transmission, Deluge)","descEn":"Five new service connectors land on the Services tab: Prowlarr (indexer), NZBGet / SABnzbd / Transmission / Deluge (download-clients). They cover authentication and connection testing only — actions (queue/history/pause/etc.) will be exposed by separate plugins talking to these connectors. Each ships with a typed test() that distinguishes auth failures from network errors and surfaces protocol-specific cases like Deluge''s daemon-detached state and Transmission''s CSRF challenge.","descFr":"Cinq nouveaux connecteurs de service arrivent dans l''onglet Services : Prowlarr (indexer), NZBGet / SABnzbd / Transmission / Deluge (download-clients). Ils couvrent uniquement l''authentification et le test de connexion — les actions (queue/history/pause/etc.) seront exposées par des plugins séparés via ces connecteurs. Chacun embarque un test() typé qui distingue les échecs d''auth des erreurs réseau et surface les cas spécifiques au protocole, comme l''état daemon-détaché de Deluge ou le challenge CSRF de Transmission."},{"type":"feat","titleEn":"Searchable service-type picker with provider icons + Untested badge","titleFr":"Sélecteur de type de service avec recherche, icônes et pastille Non testé","descEn":"The service-creation modal now opens a Headless UI Combobox instead of a native <select>, with a search input, provider icons rendered inline, and an amber ''Untested'' pill on connectors that the maintainer has not yet validated against a real instance. Picking an untested connector shows a one-click GitHub feedback link prefilled with the connector name — the badge is removed in the same commit that confirms the integration works.","descFr":"Le modal de création de service ouvre maintenant un Combobox Headless UI au lieu d''un <select> natif, avec une barre de recherche, les icônes provider rendues inline, et une pastille amber « Non testé » sur les connecteurs pas encore validés sur vraie instance. Choisir un connecteur non testé affiche un lien GitHub de retour prérempli avec le nom du connecteur — la pastille est retirée dans le même commit qui confirme que l''intégration fonctionne."},{"type":"feat","titleEn":"Support module extracted to a standalone plugin","titleFr":"Module Support extrait en plugin autonome","descEn":"The legacy in-core Support module is now shipped as `Oscarr-Plugin-Support`, removable like any other plugin. The migration carries an export of existing tickets so admins can install the plugin and keep their data, while keeping the core lean and aligned with the plugin-first vision (only auth / UI shell / notifications / plugin engine stay in core).","descFr":"Le module Support historiquement dans le core est maintenant livré sous forme de plugin `Oscarr-Plugin-Support`, désinstallable comme n''importe quel autre. La migration embarque un export des tickets existants pour que les admins puissent installer le plugin et garder leurs données, tout en gardant le core lean et aligné avec la vision plugin-first (seuls auth / UI shell / notifications / moteur plugins restent dans le core)."},{"type":"fix","titleEn":"SonarCloud reliability sweep — 53 bugs cleared","titleFr":"Nettoyage SonarCloud — 53 bugs corrigés","descEn":"Three refactor tiers landed in this cycle (mechanical sweep, cosmetic batch, redundant cast removal) and all 53 outstanding SonarCloud bugs are cleared. Pure code-health work — no behavioural change expected.","descFr":"Trois tiers de refactor ce cycle (sweep mécanique, batch cosmétique, drop des casts redondants) et les 53 bugs SonarCloud en attente sont corrigés. Pur travail de qualité — aucun changement de comportement attendu."},{"type":"fix","titleEn":"Log injection sanitizer hardened","titleFr":"Sanitiseur de log injection durci","descEn":"CodeQL was failing to recognise the log sanitizer; rewriting it as explicit per-channel branches with separate replace() calls satisfies the static analyzer and removes the dead suppression. Closes part of the security code-scanning queue (#182).","descFr":"CodeQL ne reconnaissait pas le sanitiseur de log ; le réécrire en branches explicites par canal avec des replace() séparés satisfait l''analyseur statique et supprime la suppression morte. Ferme une partie de la queue code-scanning (#182)."},{"type":"other","titleEn":"Faster multi-arch (amd64 + arm64) release builds","titleFr":"Builds release multi-arch (amd64 + arm64) accélérés","descEn":"The release pipeline now produces both linux/amd64 and linux/arm64 images noticeably faster. The lockfile''s platform-native deps were also restored so installs on distroless / musl images stop failing.","descFr":"Le pipeline release produit maintenant les images linux/amd64 et linux/arm64 nettement plus vite. Les deps natives du lockfile ont aussi été restaurées pour que les installs sur images distroless / musl ne plantent plus."}]'
) ON CONFLICT ("version") DO NOTHING;
